import React, { useState, useRef, useEffect } from "react";
import { FiUser, FiSearch, FiHeart, FiShoppingCart, FiMenu, FiX } from "react-icons/fi";
import { FaChevronDown, FaTags } from "react-icons/fa";
import MegaMenu from "./MegaMenu";
import { useNavigate } from "react-router-dom";
import CartDrawer from "../../components/common/drawer/CartDrawer";
import { useSelector } from "react-redux";
import { Link } from "react-router-dom";

/* ─── WIRSA Logo image (embedded — works without copying to /public) ─ */
const WIRSA_LOGO_SRC = "data:image/png;base64,";

/* ─── Reusable brand block ───────────────────────────────────────── */
const WirsaLogo = ({ height = 44, showTagline = true }) => (
  <div style={{ display:"flex", flexDirection:"column", alignItems:"flex-start", gap:"2px" }}>
    <img
      src={WIRSA_LOGO_SRC}
      alt="WIRSA"
      style={{
        height: `${height}px`,
        width: "auto",
        objectFit: "contain",
        display: "block",
      }}
    />
    {showTagline && (
      <span style={{
        fontSize: "11px",
        fontWeight: 400,
        letterSpacing: "1px",
        color: "#666666",
        fontFamily: "'Poppins', sans-serif",
        lineHeight: 1,
        whiteSpace: "nowrap",
        paddingLeft: "2px",
      }}>
        Indian Groceries &amp; Sweets
      </span>
    )}
  </div>
);

/* ─── Header ─────────────────────────────────────────────────────── */
const Header = () => {
  const [menuOpen, setMenuOpen]         = useState(false);
  const [userLoggedIn, setUserLoggedIn] = useState(false);
  const [accountOpen, setAccountOpen]   = useState(false);
  const [showMegaMenu, setShowMegaMenu] = useState(false);
  const [cartOpen, setCartOpen]         = useState(false);
  const [scrolled, setScrolled]         = useState(false);
  const accountRef = useRef();
  const navigate   = useNavigate();
  const cartCount  = useSelector(state => state.cart.items.reduce((s, i) => s + i.qty, 0));

  useEffect(() => {
    const onClick = (e) => {
      if (accountRef.current && !accountRef.current.contains(e.target)) setAccountOpen(false);
    };
    document.addEventListener("mousedown", onClick);
    return () => document.removeEventListener("mousedown", onClick);
  }, []);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener("scroll", onScroll);
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  const handleLogout = () => { setUserLoggedIn(false); setAccountOpen(false); };

  return (
    <>
      <header
        className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 bg-white ${scrolled ? "navbar-scrolled" : ""}`}
        style={{
          fontFamily: "'Montserrat', sans-serif",
          boxShadow: scrolled ? undefined : "0 2px 10px rgba(0,0,0,0.08)",
          borderBottom: "1px solid #E5E5E5",
        }}
      >
        {/* ════ DESKTOP TOP ROW ════ */}
        <div className="hidden md:flex items-center gap-6 px-8 py-3 max-w-[1400px] mx-auto">

          {/* LEFT — Logo */}
          <Link to="/" className="flex-shrink-0 group" style={{ marginRight:"15px", cursor:"pointer", transition:"all 0.2s ease" }}>
            <div style={{ opacity: 1, transition:"opacity 0.2s ease" }} className="group-hover:opacity-90">
              <WirsaLogo height={44} showTagline={true} />
            </div>
          </Link>

          {/* CENTER — Search */}
          <div className="flex flex-1 min-w-0">
            <input
              type="text"
              placeholder="Search groceries, sweets, snacks..."
              className="flex-1 min-w-0 px-5 py-3 text-sm rounded-l-full focus:outline-none text-gray-700 placeholder-gray-400 border border-r-0 border-gray-200 focus:border-[#E11C2A] transition-all duration-300"
              style={{ background: "#F8F8F8", fontFamily: "'Poppins', sans-serif" }}
            />
            <button
              className="px-6 rounded-r-full text-white flex items-center gap-2 font-semibold text-sm transition-all duration-300 hover:bg-[#C91825] flex-shrink-0"
              style={{ background: "#E11C2A" }}
            >
              <FiSearch className="text-lg" />
              <span className="hidden lg:inline">Search</span>
            </button>
          </div>

          {/* RIGHT — Icons */}
          <div className="flex items-center gap-2 flex-shrink-0">
            {/* Account */}
            <div className="relative" ref={accountRef}>
              <button
                onClick={() => setAccountOpen(!accountOpen)}
                className="flex items-center gap-2 px-3 py-2 rounded-xl transition-all duration-300 hover:bg-gray-50 group"
              >
                <div className="w-8 h-8 rounded-full flex items-center justify-center transition-all duration-300 group-hover:bg-[#E11C2A] bg-gray-100">
                  <FiUser className="text-gray-600 group-hover:text-white text-base" />
                </div>
                <div className="hidden lg:block text-left">
                  <p className="text-[10px] text-gray-400 leading-tight">Account</p>
                  <p className="text-xs font-semibold text-gray-700 leading-tight">Sign In</p>
                </div>
                <FaChevronDown className="text-xs text-gray-400" />
              </button>
              {accountOpen && (
                <div className="absolute right-0 mt-2 w-48 rounded-xl shadow-xl p-2 z-50 animate-slideUp bg-white" style={{ border:"1px solid #E5E5E5" }}>
                  {!userLoggedIn ? (
                    <>
                      <button className="w-full text-left px-4 py-2.5 text-sm rounded-lg hover:bg-[#E11C2A] hover:text-white transition-all duration-300 font-medium text-gray-700"
                        onMouseDown={() => { navigate("/login"); setAccountOpen(false); }}>Login</button>
                      <button className="w-full text-left px-4 py-2.5 text-sm rounded-lg hover:bg-[#E11C2A] hover:text-white transition-all duration-300 font-medium text-gray-700"
                        onMouseDown={() => { navigate("/signup"); setAccountOpen(false); }}>Sign Up</button>
                    </>
                  ) : (
                    <>
                      <Link to="#" className="block px-4 py-2.5 text-sm rounded-lg hover:bg-[#E11C2A] hover:text-white transition-all duration-300 text-gray-700">My Profile</Link>
                      <button onClick={handleLogout} className="w-full text-left px-4 py-2.5 text-sm rounded-lg hover:bg-red-50 text-red-500 transition-all duration-300">Logout</button>
                    </>
                  )}
                </div>
              )}
            </div>

            {/* Wishlist */}
            <button className="w-10 h-10 rounded-xl flex items-center justify-center bg-gray-100 hover:bg-[#E11C2A] hover:scale-110 transition-all duration-300 group" style={{ border:"1px solid #EEEEEE" }}>
              <FiHeart className="text-gray-500 group-hover:text-white text-lg" />
            </button>

            {/* Cart */}
            <button onClick={() => setCartOpen(true)}
              className="flex items-center gap-2 px-4 py-2.5 rounded-xl text-sm font-semibold text-white transition-all duration-300 hover:bg-[#C91825] hover:scale-105"
              style={{ background:"#E11C2A", boxShadow:"0 4px 15px rgba(225,28,42,0.25)" }}>
              <FiShoppingCart className="text-lg" />
              <span className="hidden lg:inline">Cart</span>
              <span className="w-5 h-5 rounded-full bg-white text-[#E11C2A] text-xs font-black flex items-center justify-center">{cartCount}</span>
            </button>
          </div>
        </div>

        {/* ════ DESKTOP NAV STRIP ════ */}
        <nav className="hidden md:block border-t bg-gray-50" style={{ borderColor:"#EEEEEE" }} onMouseLeave={() => setShowMegaMenu(false)}>
          <div className="flex items-center justify-between px-8 py-0 max-w-[1400px] mx-auto relative">
            <div className="flex items-center gap-1">
              {[
                { label:"Home",       to:"/"  },
                { label:"Shop",       dropdown:true },
                { label:"Well Being", dropdown:true },
                { label:"Contact",    to:"#"  },
              ].map((link) =>
                link.dropdown ? (
                  <div key={link.label}
                    className="relative flex items-center gap-1.5 px-4 py-3.5 text-sm font-medium text-gray-600 hover:text-[#E11C2A] cursor-pointer nav-link group"
                    onMouseEnter={() => setShowMegaMenu(true)}>
                    <span>{link.label}</span>
                    <FaChevronDown className="text-xs text-gray-400 transition-transform duration-300 group-hover:rotate-180 group-hover:text-[#E11C2A]" />
                  </div>
                ) : (
                  <Link key={link.label} to={link.to}
                    className="px-4 py-3.5 text-sm font-medium text-gray-600 hover:text-[#E11C2A] nav-link transition-all duration-300">
                    {link.label}
                  </Link>
                )
              )}
            </div>
            {showMegaMenu && <MegaMenu />}
            <button className="deal-pill flex items-center gap-2 px-5 py-2 rounded-full text-white text-sm font-bold transition-all duration-300 hover:scale-105 hover:bg-[#C91825]"
              style={{ background:"#E11C2A", fontFamily:"'Montserrat', sans-serif" }}>
              <FaTags className="text-sm" /> Today's Deal
            </button>
          </div>
        </nav>

        {/* ════ MOBILE HEADER ════ */}
        <div className="flex md:hidden items-center justify-between px-4 py-3">
          <Link to="/" className="group" style={{ cursor:"pointer", transition:"all 0.2s ease" }}>
            <div className="group-hover:opacity-90 transition-opacity duration-200">
              <WirsaLogo height={38} showTagline={false} />
            </div>
          </Link>
          <div className="flex items-center gap-2">
            <button onClick={() => setCartOpen(true)} className="w-9 h-9 rounded-lg flex items-center justify-center" style={{ background:"#E11C2A" }}>
              <FiShoppingCart className="text-white" />
            </button>
            <button onClick={() => setMenuOpen(!menuOpen)} className="w-9 h-9 rounded-lg flex items-center justify-center bg-gray-100" style={{ border:"1px solid #E5E5E5" }}>
              {menuOpen ? <FiX className="text-gray-600" /> : <FiMenu className="text-gray-600" />}
            </button>
          </div>
        </div>
        <div className="flex md:hidden px-4 pb-3">
          <input type="text" placeholder="Search groceries, sweets..."
            className="flex-1 px-4 py-2.5 rounded-l-full text-sm text-gray-700 focus:outline-none border border-r-0 border-gray-200"
            style={{ background:"#F8F8F8" }} />
          <button className="px-4 rounded-r-full" style={{ background:"#E11C2A" }}>
            <FiSearch className="text-white" />
          </button>
        </div>
      </header>

      <div className="hidden md:block h-[116px]" />
      <div className="block md:hidden h-[112px]" />

      {/* ════ MOBILE DRAWER ════ */}
      {menuOpen && (
        <>
          <div className="fixed inset-0 bg-black/30 backdrop-blur-sm z-40 md:hidden" onClick={() => setMenuOpen(false)} />
          <div className="fixed top-0 right-0 h-full w-[75vw] max-w-xs z-50 flex flex-col md:hidden animate-slideUp bg-white" style={{ borderLeft:"1px solid #E5E5E5" }}>
            <div className="flex items-center justify-between p-5" style={{ borderBottom:"1px solid #EEEEEE" }}>
              <WirsaLogo height={36} showTagline={false} />
              <button onClick={() => setMenuOpen(false)} className="w-8 h-8 rounded-lg flex items-center justify-center bg-gray-100">
                <FiX className="text-gray-600 text-lg" />
              </button>
            </div>
            <nav className="flex-1 overflow-y-auto p-4 space-y-1">
              {[["Home","/"],["Shop","#"],["Well Being","#"],["Contact","#"]].map(([label,to])=>(
                <Link key={label} to={to} onClick={()=>setMenuOpen(false)}
                  className="flex items-center justify-between px-4 py-3 rounded-xl text-sm font-semibold text-gray-600 hover:text-[#E11C2A] hover:bg-red-50 transition-all duration-300">
                  {label}
                </Link>
              ))}
            </nav>
            <div className="p-4" style={{ borderTop:"1px solid #EEEEEE" }}>
              <button className="w-full py-3 rounded-xl font-bold text-white text-sm deal-pill" style={{ background:"#E11C2A" }}>
                Today's Deals 🔥
              </button>
            </div>
          </div>
        </>
      )}

      {/* Mobile bottom tab */}
      <div className="fixed bottom-0 left-0 right-0 z-50 md:hidden bg-white" style={{ borderTop:"1px solid #E5E5E5", boxShadow:"0 -4px 15px rgba(0,0,0,0.06)" }}>
        <div className="flex justify-around py-2">
          {[
            { Icon:FiShoppingCart, label:"Cart",    action:()=>setCartOpen(true) },
            { Icon:FiHeart,        label:"Wishlist", action:()=>{} },
            { Icon:FiUser,         label:"Account", action:()=>navigate("/login") },
            { Icon:FiMenu,         label:"More",    action:()=>setMenuOpen(!menuOpen) },
          ].map(({Icon,label,action})=>(
            <button key={label} onClick={action}
              className="flex flex-col items-center gap-0.5 text-gray-400 hover:text-[#E11C2A] transition-all duration-300 px-3 py-1">
              <Icon className="text-xl" />
              <span className="text-[10px] font-medium">{label}</span>
            </button>
          ))}
        </div>
      </div>

      <CartDrawer cartOpen={cartOpen} setCartOpen={setCartOpen} />
    </>
  );
};

export default Header;